#include <bits/stdc++.h>
using namespace std;
int main(){
    int n, m;
    cin >> n >> m;
    vector<vector<int>> prerequisites(m, vector<int>(2));
    for(int i = 0; i < m; i++)
        cin >> prerequisites[i][0] >> prerequisites[i][1];

    vector<int> graph[n];
    vector<int> indegree(n, 0);
    for(auto& pr : prerequisites){
        graph[pr[1]].push_back(pr[0]);
        indegree[pr[0]]++;
    }

    queue<int> q;
    for(int i = 0; i < n; i++)
        if(indegree[i] == 0)
            q.push(i);
    vector<int> result;

    while(!q.empty()){
        int node = q.front(); q.pop();
        result.push_back(node);
        for(int neighbor : graph[node]){
            indegree[neighbor]--;
            if(indegree[neighbor] == 0)
                q.push(neighbor);
        }
    }

    if(result.size() != n){
        cout << "IMPOSSIBLE";
    }else{
        for(int num : result)
            cout << num << " ";
    }
    return 0;
}
